parameters.jsCode:
const rows = $input.all();

if (rows.length === 0) {
 return [{
 json: {
 error: "Dataset is empty"
 }
 }];
}

const data = rows.map(r => r.json);

const columns = Object.keys(data[0]);

const totalRows = data.length;
const totalColumns = columns.length;

const missingValues = {};

for (const col of columns) {
 missingValues[col] = 0;

 for (const row of data) {

 const value = row[col];

 if (
 value === null ||
 value === undefined ||
 value === "" ||
 value === "NA" ||
 value === "NaN"
 ) {
 missingValues[col]++;
 }
 }
}


const uniqueRows = new Set(
 data.map(r => JSON.stringify(r))
);

const duplicateRows = totalRows - uniqueRows.size;


const numericColumns = [];
const categoricalColumns = [];

for (const col of columns) {

 let numeric = true;

 for (const row of data) {

 const value = row[col];

 if (
 value === "" ||
 value === null ||
 value === undefined
 ) {
 continue;
 }

 if (isNaN(Number(value))) {
 numeric = false;
 break;
 }
 }

 if (numeric)
 numericColumns.push(col);
 else
 categoricalColumns.push(col);
}

return [{
 json: {

 rows: totalRows,

 columns: totalColumns,

 columnNames: columns,

 duplicateRows,

 missingValues,

 numericColumns,

 categoricalColumns

 }
}];

